  /*
    {{page-title "Emoji"}}
  
  <h1>Emoji</h1>
  
  {{#if this.model.allowed}}
  
  <p>AresMUSH supports standard <a href="https://unicode.org/emoji/charts/full-emoji-list.html" target="_blank" rel="nofollow noopener">Unicode emoji</a>.  You can copy/paste them from this list, or use the names like <code>:grin:</code>.</p>  
  
  <p>Some MUSH clients may not be able to display emoji.  If your client cannot display any Unicode/UTF-8 characters at all, you probably want to turn on <LinkTo @route='help-topic' @model='ascii'>ASCII Mode</LinkTo>  If you just have trouble with emoji, you can <LinkTo @route='help-topic' @model='emoji'>turn them off</LinkTo> without affecting other special characters.</p>
  
  <div class="toc">
    <b>Table of Contents</b>
    <ul>
      <li><a href="#quick">Quickref</a></li>
      <li><a href="#emoji">Emoji</a></li>
      <li><a href="#smileys">Smileys</a></li>
    </ul>
  </div>
  
  
  <a name="quick"></a>
  
  <h2>Quickref</h2>
  
  
  <div class="emoji-row">
  {{#each this.model.aliases as |emoji|}}
    <div class="emoji-example">
      <div class="emoji-symbol">{{emoji.display}}</div>
      <div class="emoji-name">:{{emoji.name}}:</div>
    </div>
  {{/each}}
  </div>
  
  
  
  <a name="emoji"></a>
  
  <h2>Emoji</h2>
  
  
  <div class="emoji-row">
  {{#each this.model.emoji as |emoji|}}
    <div class="emoji-example">
      <div class="emoji-symbol">{{emoji.display}}</div>
      <div class="emoji-name">:{{emoji.name}}:</div>
    </div>
  {{/each}}
  </div>
  
  
  <a name="smileys"></a>
  
  <h2>Smileys</h2>
  
  
  <div class="emoji-row">
  {{#each this.model.smileys as |emoji|}}
    <div class="emoji-example">
      <div><code>{{{emoji.name}}}</code></div>
      <div class="emoji-symbol">{{emoji.display}}</div>
    </div>
  {{/each}}
  </div>
  
  
  {{else}}
  <p>This game does not have emoji enabled.  :sadface:</p>
  {{/if}}
  
  */
