  /*
    {{page-title 'Edit Game'}}
  <h1>Edit Game Information</h1>
  
  <p>This information will be used on your web portal and in the <a href="https://arescentral.aresmush.com">AresCentral Game Directory</a> to advertise your game.</p>
  
        <div class="alert alert-info">Only public games are advertised on AresCentral.  Private games will not appear on the AresCentral game list, but they can still be registered to activate other AresCentral features (like player handles).  Only players with a character on the game will see details for a private game on AresCentral. Admins can register a private game with AresCentral using the <code>game/register</code> command. </div>
  
  
  <div class="form-item">
    <div class="form-item-label">Name:</div>
    <div class="form-item-entry"><Input @type="text" size={{25}} id="name" @value={{this.model.config.name}} /></div>
  </div>
  
  <div class="form-item">
    <div class="form-item-label">Website:</div>
    <div class="form-item-entry">
     <Input @type="text" size={{25}} id="website" @value={{this.model.config.website}} />
      <div class="hint">(Leave blank to use your web portal address.)</div>
     </div>
  </div>
  
  <div class="form-item">
    <div class="form-item-label">Category:</div>
    <div class="form-item-entry">
     <PowerSelect @selected={{this.model.config.category}} @options={{this.model.category_options}} @onChange={{this.categoryChanged}} as |category|>
       {{category}}
     </PowerSelect>
    </div>
  </div>
  
  <div class="form-item">
    <div class="form-item-label">Status:</div>
    <div class="form-item-entry">
      <PowerSelect @selected={{this.model.config.status}} @options={{this.model.status_options}} @onChange={{this.statusChanged}} as |status|>
        {{status}}
      </PowerSelect>                
    </div>
  </div>
  
  <div class="form-item">
    <div class="form-item-label">Public Game?</div>
    <div class="form-item-entry">
      <div>
        <Input @type="checkbox" @checked={{this.model.config.public_game}} />   
      </div>
    </div>              
  </div>
  
  <div class="form-item">
    <div class="form-item-label">Description:</div>
    <div class="form-item-entry">
      <MarkdownEditor @text={{this.model.config.description}} />     
    </div>
  </div>
  
  
  <p><b>:</b></p>
  
  
  
  
  <div class="action-buttons">
    <LinkTo @route="setup" class="btn btn-secondary">Cancel</LinkTo>
    <button {{on 'click' this.save}} class="btn btn-primary">Save</button>
  </div>
  
  {{#if this.warning}}
  <div class="alert alert-warning">
    <AnsiFormat @text={{this.warning}} />
  </div>
  {{/if}}
  
  <FlashMessages />
  {{outlet}}
  */
