  /*
    {{page-title 'Select Plugins'}}
  <h1>Select Plugins</h1>
  
  <p>Some plugins are designed to be easily disabled and enabled.  Please read the <a href="https://aresmush.com/tutorials/config/plugins.html">Enabling and Disabling Plugins</a> tutorial to learn more.</p>
  
  <table>
  {{#each this.model as |plugin|}}
  
  <tr>
    <td><span class="text">{{plugin.name}}</span></td>
    <td>
    <Input @type="checkbox" @checked={{plugin.selected}} /> 
    </td>
  
    <td>
    {{#if plugin.optional}}
    <span class="badge bg-success">optional</span>
    {{else}}
    <span class="badge bg-danger">required</span>
    {{/if}}
    </td>
  </tr>
    
  
  {{/each}}
  
  </table>
  
  
  <div class="action-buttons">
      <LinkTo @route="setup" class="btn btn-secondary">Cancel</LinkTo>
  
      <button {{on 'click' this.save}} class="btn btn-primary">Save</button>
  </div>
  
  
  {{outlet}}
  */
