  /*
    <h1>Server Information</h1>
  
    {{#if this.versionWarning}}
      <div class="alert alert-warning">
        <p><i class="fas fa-exclamation-triangle"></i> The website and game have different versions. This can cause unpredictable errors. Try doing a 'force refresh' on this page in your browser, or load the page in private/incognito mode. If the problem persists, the web portal must have failed the last upgrade.</p>
      </div>
    {{/if}}
    
  <table>
    <tr>
      <td class="col-xs-3"><b>Game Engine Version:</b> </td>
      <td>{{this.mushVersion}}</td>
    </tr>
    
    <tr>
      <td class="col-xs-3"><b>Web Portal Version:</b> </td>
      <td>{{this.webPortalVersion}}</td>
    </tr>
    
    <tr>
      <td class="col-xs-3"><b>Server Uptime:</b> </td>
      <td>{{this.model.server_uptime}} (started {{this.model.server_start}})</td>
    </tr>
    
    <tr>
      <td class="col-xs-3"><b>Database Stats:</b> </td>
      <td>
        <ul>
          <li>Characters: {{this.model.num_characters}}</li>
          <li>Rooms: {{this.model.num_rooms}}</li>
          <li>Exits: {{this.model.num_exits}}</li>
        </ul>
      </td>
    </tr>
    
    <tr>
      <td class="col-xs-3"><b>Plugins Installed:</b> </td>
      <td>
          {{#each this.model.plugins as |plugin|}}
          <span class="server-plugin">{{plugin}}</span>
          {{/each}}
      </td>
    </tr>
    
    <tr>
      <td class="col-xs-3"><b>Database Migrations:</b> </td>
      <td>{{#each this.model.migrations as |migration|}}
        <span class="server-migration">{{migration}}</span>
        {{/each}}
      </td>
    </tr>
    
    <tr>
      <td class="col-xs-3"><b>License</b></td>
      <td><a href="https://www.aresmush.com/license">https://www.aresmush.com/license</a></td>
    </tr>
    
  </table>
  */
